@app.route('/saml/sso', methods=['GET', 'POST'])
def sso():
    """Handle SSO requests"""
    
    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest')
        relay_state = request.args.get('RelayState', '')
    else:
        saml_request = request.form.get('SAMLRequest')
        relay_state = request.form.get('RelayState', '')
    
    if not saml_request:
        return "Missing SAMLRequest parameter", 400
    
    # Decode and parse the SAML request
    try:
        decoded_request = base64.b64decode(saml_request)
        try:
            inflated_request = zlib.decompress(decoded_request, -15)
        except:
            inflated_request = decoded_request
        
        root = etree.fromstring(inflated_request)
        
        request_id = root.get('ID')
        acs_url = root.get('AssertionConsumerServiceURL')
        issuer_elem = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
        issuer = issuer_elem.text if issuer_elem is not None else ''
        
    except Exception as e:
        return f"Error parsing SAML request: {str(e)}", 400
    
    # Check if user is authenticated
    session_id = request.cookies.get('idp_session')
    if session_id and session_id in SESSIONS:
        user_email = SESSIONS[session_id]['user']
        user_data = USERS.get(user_email)
        
        if user_data:
            # Generate SAML response
            saml_response = create_saml_response(
                user_email,
                user_data['attributes'],
                acs_url,
                request_id,
                issuer
            )
            
            # Encode response
            encoded_response = base64.b64encode(saml_response.encode('utf-8')).decode('utf-8')
            
            # Send response via HTTP POST
            html = f'''
            <html>
                <body onload="document.forms[0].submit()">
                    <form method="POST" action="{acs_url}">
                        <input type="hidden" name="SAMLResponse" value="{encoded_response}"/>
                        <input type="hidden" name="RelayState" value="{relay_state}"/>
                        <noscript>
                            <input type="submit" value="Continue"/>
                        </noscript>
                    </form>
                </body>
            </html>
            '''
            return html
    
    # Show login form
    login_html = f'''
    <html>
        <body>
            <h2>Login to IdP</h2>
            <form method="POST" action="/saml/login">
                <input type="hidden" name="SAMLRequest" value="{saml_request}"/>
                <input type="hidden" name="RelayState" value="{relay_state}"/>
                <label>Email: <input type="text" name="username"/></label><br/>
                <label>Password: <input type="password" name="password"/></label><br/>
                <input type="submit" value="Login"/>
            </form>
            <p>Test credentials: user@example.com / password123</p>
        </body>
    </html>
    '''
    return login_html


@app.route('/saml/login', methods=['POST'])
def login():
    """Handle login form submission"""
    username = request.form.get('username')
    password = request.form.get('password')
    saml_request = request.form.get('SAMLRequest')
    relay_state = request.form.get('RelayState', '')
    
    # Validate credentials
    user = USERS.get(username)
    if user and user['password'] == password:
        # Create session
        session_id = uuid.uuid4().hex
        SESSIONS[session_id] = {
            'user': username,
            'created': datetime.utcnow()
        }
        
        # Redirect back to SSO endpoint
        response = make_response(redirect(f"/saml/sso?SAMLRequest={saml_request}&RelayState={relay_state}"))
        response.set_cookie('idp_session', session_id, httponly=True, secure=False)
        return response
    else:
        return "Invalid credentials", 401


@app.route('/saml/slo', methods=['GET', 'POST'])
def slo():
    """Handle Single Logout requests"""
    
    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest')
        relay_state = request.args.get('RelayState', '')
    else:
        saml_request = request.form.get('SAMLRequest')
        relay_state = request.form.get('RelayState', '')
    
    # Clear session
    session_id = request.cookies.get('idp_session')
    if session_id and session_id in SESSIONS:
        del SESSIONS[session_id]
    
    response = make_response("Logged out successfully")
    response.set_cookie('idp_session', '', expires=0)
    return response


